+  CERTIFICATION_LABEL_ORDER,
+  PRODUCT_ATTESTATION_META,
+  PRODUCT_ATTESTATION_ORDER,
+  chipDisplay,
+  getAvailableEntries,
+  getCertValue,
+  getProductAttestationValue,
+  hasCertifiableChip,
+  statusTextWhenNoChip,
+  useProcertusCategorization,
+} from "@procertus-ui/procertus-categorization";
+import type {
+  AvailableEntry,
+  AvailableEntryKey,
+  CertificationLabelKey,
+  ProductAttestationKey,
+  TreeNode,
+} from "@procertus-ui/procertus-categorization";
+import {
+  Badge,
+  Button,
+  Card,
+  CardContent,
+  CardDescription,
+  CardHeader,
+  CardTitle,
+  Field,
+  FieldContent,
+  FieldLabel,
