+} from "@procertus-ui/ui";
+import {
+  CertificationBadgeRow,
+  CertificationIntentPicker,
+  DraftRequestList,
+  OnboardingStepper,
+  ProductMultiSelect,
+  ProductTreePanel,
+  RequestPackageReview,
+  StepLayout,
+  defaultCertificationIntentOptionsEn,
+} from "@procertus-ui/ui-lib";
+import type {
+  CertificationBadgeItem,
+  CertificationIntentId,
+  DraftRequestItem,
+  OnboardingStepperStep,
+  ProductMultiSelectOption,
+  ProductTreeNode,
+  ProductTreeProductNode,
+  RequestPackageRow,
+} from "@procertus-ui/ui-lib";
+import { useMemo, useState } from "react";
+
+const STEP_IDS = ["intent", "details", "drafts", "review"] as const;
+
+const CERTIFICATION_ENTRY_IDS = new Set<AvailableEntryKey>(CERTIFICATION_LABEL_ORDER);
+const PRODUCT_REQUIRED_INTENTS = new Set<CertificationIntentId>([
+  "product-certification",
+  "procertus",
+]);
+const OPTIONAL_PRODUCT_INTENTS = new Set<CertificationIntentId>([
+  "atg",
+  "epd",
+  "partijkeuring",
+]);
+
+export type CertificationWizardDraft = {
+  id: string;
+  entryId: AvailableEntryKey | CertificationIntentId;
+  label: string;
+  shortLabel: string;
+  productId?: string;
+  productLabel?: string;
+  productPath?: string;
+  value?: string;
+  context?: string;
+};
+
+export type CertificationRequestWizardProps = {
+  mode: "onboarding" | "authenticated";
+  initialDrafts?: CertificationWizardDraft[];
+  onCancel?: () => void;
+  onComplete: (drafts: CertificationWizardDraft[]) => void;
+};
+
+type ProductIndexEntry = {
+  node: TreeNode;
+  path: string[];
+};
+
+type ProductAvailability = {
+  available: boolean;
+  value?: string;
+  reason?: string;
+};
+
+function isCertificationKey(key: AvailableEntryKey): key is CertificationLabelKey {
+  return CERTIFICATION_LABEL_ORDER.includes(key as CertificationLabelKey);
+}
+
+function isAttestationKey(key: AvailableEntryKey): key is ProductAttestationKey {
+  return PRODUCT_ATTESTATION_ORDER.includes(key as ProductAttestationKey);
+}
+
+function normalizeQuery(value: string) {
+  return value.trim().toLocaleLowerCase("nl-BE");
+}
+
+function entryLabelForIntent(
+  intent: CertificationIntentId | undefined,
+  availableEntries: readonly AvailableEntry[],
+) {
+  if (!intent) return undefined;
+  if (intent === "product-certification") return "Productcertificatie";
+  return availableEntries.find((entry) => entry.id === intent)?.label ?? intent;
+}
+
+function buildProductIndex(nodes: readonly TreeNode[], prefix: string[] = []): Map<string, ProductIndexEntry> {
+  const pairs = nodes.flatMap((node): Array<[string, ProductIndexEntry]> => {
+    const path = [...prefix, node.label];
+    if (node.kind === "product") {
+      return [[node.id, { node, path }]];
+    }
+    return buildProductIndex(node.children ?? [], path).entries().toArray();
+  });
+  return new Map(pairs);
+}
+
+function getAvailability(node: TreeNode, entry: AvailableEntry): ProductAvailability {
+  const key = entry.productAvailabilityKey;
+  if (node.kind !== "product" || !key) {
+    return { available: false, reason: "Deze aanvraagroute is niet productgebonden." };
+  }
+  if (isCertificationKey(key) && node.certification) {
+    const value = getCertValue(node.certification, key);
+    return hasCertifiableChip(value)
+      ? { available: true, value }
+      : { available: false, value, reason: statusTextWhenNoChip(value) };
+  }
+  if (isAttestationKey(key) && node.attestations) {
+    const value = getProductAttestationValue(node.attestations, key);
+    return hasCertifiableChip(value)
+      ? { available: true, value }
+      : { available: false, value, reason: statusTextWhenNoChip(value) };
+  }
+  return { available: false, reason: "Niet beschikbaar voor dit producttype." };
+}
+
+function getAvailableProductEntries(node: TreeNode | undefined, entries: readonly AvailableEntry[]) {
+  if (!node) return [];
+  return entries
+    .filter((entry) => entry.productAvailabilityKey != null)
+    .map((entry) => ({ entry, availability: getAvailability(node, entry) }))
+    .filter(({ availability }) => availability.available);
+}
+
+function primaryIntentAvailable(
+  node: TreeNode,
+  intent: CertificationIntentId | undefined,
+  entries: readonly AvailableEntry[],
+) {
+  if (!intent) return { available: true, label: "Selecteerbaar" };
+  if (intent === "product-certification") {
+    const hasProductCertification = entries
+      .filter((entry) => CERTIFICATION_ENTRY_IDS.has(entry.id))
+      .some((entry) => getAvailability(node, entry).available);
+    return hasProductCertification
+      ? { available: true, label: "Productcertificatie mogelijk" }
+      : {
+          available: false,
+          label: "Niet beschikbaar",
+          reason: "Geen CE-, BENOR- of SSD-traject beschikbaar voor dit producttype.",
+        };
+  }
+  const selectedEntry = entries.find((entry) => entry.id === intent);
+  if (!selectedEntry?.productAvailabilityKey) {
+    return { available: true, label: "Contextaanvraag" };
+  }
+  const availability = getAvailability(node, selectedEntry);
+  return availability.available
+    ? { available: true, label: `${selectedEntry.shortLabel} beschikbaar` }
+    : {
+        available: false,
+        label: "Niet beschikbaar",
+        reason: `${selectedEntry.shortLabel}: ${availability.reason ?? "niet aangeboden voor dit producttype."}`,
+      };
+}
+
+function pathMatches(path: readonly string[], query: string) {
+  if (!query) return true;
+  return path.some((part) => part.toLocaleLowerCase("nl-BE").includes(query));
+}
+
+function toProductTreeNodes({
+  nodes,
+  entries,
+  intent,
+  selectedProductId,
+  query,
+  pathPrefix = [],
+}: {
+  nodes: readonly TreeNode[];
+  entries: readonly AvailableEntry[];
+  intent: CertificationIntentId | undefined;
+  selectedProductId: string | undefined;
+  query: string;
+  pathPrefix?: string[];
+}): ProductTreeNode[] {
+  return nodes.flatMap((node): ProductTreeNode[] => {
+    const path = [...pathPrefix, node.label];
+    if (node.kind === "product") {
+      if (!pathMatches(path, query)) return [];
+      const availability = primaryIntentAvailable(node, intent, entries);
+      return [
+        {
+          kind: "product",
+          id: node.id,
+          label: node.label,
+          productTypeId: node.productTypeStreamLabel,
+          description: path.slice(0, -1).join(" › "),
+          selectable: availability.available,
+          statusLabel: availability.label,
+          unavailableReason: availability.reason,
+          selected: selectedProductId === node.id,
+        },
+      ];
+    }
+
+    const children = toProductTreeNodes({
+      nodes: node.children ?? [],
+      entries,
+      intent,
+      selectedProductId,
+      query,
+      pathPrefix: path,
+    });
+    const groupMatches = pathMatches(path, query);
+    if (!groupMatches && children.length === 0) return [];
+    return [{ kind: "group", id: node.id, label: node.label, children: groupMatches && !query ? children : children }];
+  });
+}
+
+function badgeItemsForDraft(draft: CertificationWizardDraft): CertificationBadgeItem[] {
+  return [
+    {
+      id: draft.id,
+      shortLabel: draft.shortLabel,
+      presentation: "chip",
+      text: draft.value,
+    },
+  ];
+}
+
+function createDraftsForProduct({
+  selectedEntryIds,
+  availableEntries,
+  product,
+}: {
+  selectedEntryIds: readonly string[];
+  availableEntries: readonly AvailableEntry[];
+  product: ProductIndexEntry;
+}): CertificationWizardDraft[] {
+  return selectedEntryIds.flatMap((entryId) => {
+    const entry = availableEntries.find((candidate) => candidate.id === entryId);
+    if (!entry) return [];
+    const availability = getAvailability(product.node, entry);
+    if (!availability.available) return [];
+    return [
+      {
+        id: `${product.node.id}-${entry.id}`,
+        entryId: entry.id,
+        label: entry.label,
+        shortLabel: entry.shortLabel,
+        productId: product.node.id,
+        productLabel: product.node.label,
+        productPath: product.path.slice(0, -1).join(" › "),
+        value: availability.value ? chipDisplay(entry.shortLabel, availability.value) : undefined,
+      },
+    ];
+  });
+}
+
+function createContextDraft({
+  intent,
+  availableEntries,
+  requestText,
+  selectedProduct,
+}: {
+  intent: CertificationIntentId;
+  availableEntries: readonly AvailableEntry[];
+  requestText: string;
+  selectedProduct?: ProductIndexEntry;
+}): CertificationWizardDraft[] {
+  const entry = availableEntries.find((candidate) => candidate.id === intent);
+  const label = entry?.label ?? entryLabelForIntent(intent, availableEntries) ?? intent;
+  const shortLabel = entry?.shortLabel ?? label;
+  return [
+    {
+      id: selectedProduct ? `${selectedProduct.node.id}-${intent}` : `context-${intent}`,
+      entryId: intent,
+      label,
+      shortLabel,
+      productId: selectedProduct?.node.id,
+      productLabel: selectedProduct?.node.label,
+      productPath: selectedProduct?.path.slice(0, -1).join(" › "),
+      context: requestText,
+    },
+  ];
+}
+
+function getOptionText(entry: AvailableEntry, value: string | undefined) {
+  const meta =
+    isCertificationKey(entry.id)
+      ? CERTIFICATION_LABEL_META[entry.id]
+      : isAttestationKey(entry.id)
+        ? PRODUCT_ATTESTATION_META[entry.id]
+        : undefined;
+  const suffix = value ? ` Beschikbaarheid: ${chipDisplay(entry.shortLabel, value)}.` : "";
+  return `${meta?.description ?? entry.description}${suffix}`;
+}
+
+export function CertificationRequestWizard({
+  mode,
+  initialDrafts = [],
+  onCancel,
+  onComplete,
+}: CertificationRequestWizardProps) {
+  const { doc, groupIds } = useProcertusCategorization();
+  const availableEntries = useMemo(() => getAvailableEntries(doc), [doc]);
+  const productIndex = useMemo(() => buildProductIndex(doc.clusters), [doc.clusters]);
+  const [activeStep, setActiveStep] = useState(0);
+  const [intent, setIntent] = useState<CertificationIntentId | undefined>();
+  const [expandedIds, setExpandedIds] = useState<string[]>(() => groupIds.slice(0, 4));
+  const [searchValue, setSearchValue] = useState("");
+  const [selectedProductId, setSelectedProductId] = useState<string>();
+  const [selectedEntryIds, setSelectedEntryIds] = useState<string[]>([]);
+  const [requestText, setRequestText] = useState("");
+  const [drafts, setDrafts] = useState<CertificationWizardDraft[]>(initialDrafts);
+
+  const selectedProduct = selectedProductId ? productIndex.get(selectedProductId) : undefined;
+  const selectedIntentLabel = entryLabelForIntent(intent, availableEntries);
+  const productRequired = intent ? PRODUCT_REQUIRED_INTENTS.has(intent) : false;
+  const optionalProduct = intent ? OPTIONAL_PRODUCT_INTENTS.has(intent) : false;
+  const detailsUseProductTree = productRequired || optionalProduct;
+  const productEntries = getAvailableProductEntries(selectedProduct?.node, availableEntries);
+  const canUseFreeform = intent ? !productRequired : false;
+  const canContinueDetails =
+    productRequired
+      ? selectedProduct != null && selectedEntryIds.length > 0
+      : canUseFreeform && requestText.trim().length >= 12;
+
+  const steps: OnboardingStepperStep[] = [
+    {
+      id: STEP_IDS[0],
+      title: "Intent",
+      description: selectedIntentLabel ?? "Kies wat je nodig hebt",
+    },
+    {
+      id: STEP_IDS[1],
+      title: productRequired ? "Product" : "Context",
+      description: selectedProduct?.node.label ?? (productRequired ? "Zoek in de beslissingsboom" : "Beschrijf de aanvraag"),
+    },
+    {
+      id: STEP_IDS[2],
+      title: "Drafts",
+      description: drafts.length === 1 ? "1 conceptaanvraag" : `${drafts.length} conceptaanvragen`,
+    },
+    {
+      id: STEP_IDS[3],
+      title: "Review",
+      description: "Controleer het pakket",
+    },
+  ];
+
+  const treeNodes = useMemo(
+    () =>
+      toProductTreeNodes({
+        nodes: doc.clusters,
+        entries: availableEntries,
+        intent,
+        selectedProductId,
+        query: normalizeQuery(searchValue),
+      }),
+    [availableEntries, doc.clusters, intent, searchValue, selectedProductId],
+  );
+
+  const productOptions: ProductMultiSelectOption[] = useMemo(
+    () =>
+      productEntries.map(({ entry, availability }) => ({
+        id: entry.id,
+        label: entry.label,
+        description: getOptionText(entry, availability.value),
+      })),
+    [productEntries],
+  );
+
+  const draftItems: DraftRequestItem[] = drafts.map((draft) => ({
+    id: draft.id,
+    title: draft.productLabel ? `${draft.label} voor ${draft.productLabel}` : draft.label,
+    subtitle: draft.productPath ?? "Niet-productgebonden aanvraag",
+    details: <CertificationBadgeRow items={badgeItemsForDraft(draft)} />,
+  }));
+
+  const reviewRows: RequestPackageRow[] = [
+    { id: "intent", label: "Startintentie", value: selectedIntentLabel ?? "Nog niet gekozen" },
+    { id: "mode", label: "Context", value: mode === "onboarding" ? "Anonieme onboarding" : "Aangemelde aanvraag" },
+    ...drafts.map((draft, index) => ({
+      id: draft.id,
+      label: `Aanvraag ${index + 1}`,
+      value: draft.productLabel ? `${draft.label} · ${draft.productLabel}` : draft.label,
+    })),
+  ];
+
+  const replaceDraftsFromDetails = () => {
+    if (!intent) return;
+    const nextDrafts =
+      selectedProduct && selectedEntryIds.length > 0
+        ? createDraftsForProduct({
+            selectedEntryIds,
+            availableEntries,
+            product: selectedProduct,
+          })
+        : createContextDraft({
+            intent,
+            availableEntries,
+            requestText,
+            selectedProduct,
+          });
+    setDrafts((prev) => {
+      const existingById = new Map(prev.map((draft) => [draft.id, draft] as const));
+      for (const draft of nextDrafts) {
+        existingById.set(draft.id, draft);
+      }
+      return Array.from(existingById.values());
+    });
+  };
+
+  const goNext = () => {
+    if (activeStep === 1) {
+      replaceDraftsFromDetails();
+    }
+    if (activeStep === steps.length - 1) {
+      onComplete(drafts);
+      return;
+    }
+    setActiveStep((step) => Math.min(step + 1, steps.length - 1));
+  };
+
+  const primaryDisabled =
+    (activeStep === 0 && !intent) ||
+    (activeStep === 1 && !canContinueDetails) ||
+    (activeStep >= 2 && drafts.length === 0);
+
+  const selectedProductAvailabilityCopy =
+    selectedProduct && intent
+      ? primaryIntentAvailable(selectedProduct.node, intent, availableEntries)
+      : undefined;
+
+  return (
+    <StepLayout
+      className="max-w-6xl"
+      variant="wizard"
+      stepper={<OnboardingStepper steps={steps} activeStep={activeStep} interactive={false} />}
+      title={
+        activeStep === 0
+          ? "Waarvoor wil je een aanvraag starten?"
+          : activeStep === 1
+            ? productRequired
+              ? "Selecteer het producttype"
+              : "Beschrijf de aanvraagcontext"
+            : activeStep === 2
+              ? "Conceptaanvragen"
+              : "Aanvraagpakket controleren"
+      }
+      description={
+        activeStep === 0
+          ? "We starten met de inhoudelijke aanvraag. Account- en organisatieactivatie komen pas nadat je zeker bent dat je dit pakket wilt indienen."
+          : activeStep === 1
+            ? productRequired
+              ? "Alle productcategorieën blijven zichtbaar. Producttypes waarvoor de gekozen intentie niet beschikbaar is, tonen waarom ze niet gekozen kunnen worden."
+              : "Niet elke attestering begint bij een product. Geef eerst de aanvraagcontext; voeg optioneel een product toe wanneer dat helpt."
+            : activeStep === 2
+              ? "Een wizardrun kan meerdere conceptaanvragen toevoegen wanneer het gekozen product meerdere beschikbare certificaties of attesten ondersteunt."
+              : "Dit is de samenvatting die terugkeert naar de onboarding-intake of naar de aangemelde aanvraaglijst."
+      }
+      stepLabel={`Stap ${activeStep + 1} van ${steps.length}`}
+      backAction={
+        activeStep > 0
+          ? { label: "Terug", onClick: () => setActiveStep((step) => Math.max(0, step - 1)) }
+          : onCancel
+            ? { label: "Annuleren", onClick: onCancel }
+            : undefined
+      }
+      secondaryAction={
+        activeStep === 2
+          ? {
+              label: "Nog een aanvraag toevoegen",
+              onClick: () => {
+                setSelectedProductId(undefined);
+                setSelectedEntryIds([]);
+                setSearchValue("");
+                setActiveStep(0);
+              },
+            }
+          : undefined
+      }
+      primaryAction={{
+        label: activeStep === steps.length - 1 ? "Gebruik dit pakket" : "Verder",
+        onClick: goNext,
+        disabled: primaryDisabled,
+      }}
+    >
+      {activeStep === 0 ? (
+        <CertificationIntentPicker
+          value={intent}
+          onValueChange={(nextIntent) => {
+            setIntent(nextIntent);
+            setSelectedProductId(undefined);
+            setSelectedEntryIds([]);
+            setRequestText("");
+          }}
+          options={defaultCertificationIntentOptionsEn}
+        />
+      ) : null}
+
+      {activeStep === 1 ? (
+        <div className="space-y-4">
+          {canUseFreeform ? (
+            <Card>
+              <CardHeader>
+                <CardTitle>Aanvraagcontext</CardTitle>
+                <CardDescription>
+                  Voor {selectedIntentLabel} volstaat in dit prototype een korte beschrijving. Een productselectie
+                  is optioneel waar het Procertus-model productinformatie bevat.
+                </CardDescription>
+              </CardHeader>
+              <CardContent>
+                <Field>
+                  <FieldLabel htmlFor="request-context">Beschrijf de aanvraag</FieldLabel>
+                  <FieldContent>
+                    <Textarea
+                      id="request-context"
+                      value={requestText}
+                      onChange={(event) => setRequestText(event.target.value)}
+                      placeholder="Bijvoorbeeld: technisch attest voor een innovatieve toepassing op een concrete werf..."
+                      className="min-h-28"
+                    />
+                  </FieldContent>
+                </Field>
+              </CardContent>
+            </Card>
+          ) : null}
+
+          {detailsUseProductTree ? (
+            <div className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)]">
+              <ProductTreePanel
+                className="max-w-none"
+                title="Product zoeken"
+                description="Drill down in de Procertus-beslissingsboom of filter op productnaam."
+                searchValue={searchValue}
+                onSearchChange={setSearchValue}
+                searchPlaceholder="Zoek product of categorie..."
+                nodes={treeNodes}
+                expandedIds={expandedIds}
+                onToggle={(groupId, open) => {
+                  setExpandedIds((prev) => {
+                    const set = new Set(prev);
+                    if (open) set.add(groupId);
+                    else set.delete(groupId);
+                    return Array.from(set);
+                  });
+                }}
+                onSelectProduct={(product: ProductTreeProductNode) => {
+                  setSelectedProductId(product.id);
+                  const selected = productIndex.get(product.id);
+                  const available = getAvailableProductEntries(selected?.node, availableEntries);
+                  const preferred =
+                    intent === "product-certification"
+                      ? available.filter(({ entry }) => CERTIFICATION_ENTRY_IDS.has(entry.id))
+                      : available.filter(({ entry }) => entry.id === intent);
+                  setSelectedEntryIds((preferred.length ? preferred : available.slice(0, 1)).map(({ entry }) => entry.id));
+                }}
+                showSearch
+              />
+              <Card className="h-fit">
+                <CardHeader>
+                  <CardTitle>Beschikbare opties</CardTitle>
+                  <CardDescription>
+                    {selectedProduct
+                      ? selectedProductAvailabilityCopy?.available
+                        ? "Kies een of meer certificaties/attesten voor dit product."
+                        : selectedProductAvailabilityCopy?.reason
+                      : "Selecteer eerst een beschikbaar producttype."}
+                  </CardDescription>
+                </CardHeader>
+                <CardContent className="space-y-4">
+                  {selectedProduct ? (
