+        : createContextDraft({ intent, availableEntries, requestText, selectedProduct });
+
+    setDrafts((prev) => {
+      const existingById = new Map(prev.map((draft) => [draft.id, draft] as const));
+      for (const draft of nextDrafts) {
+        existingById.set(draft.id, draft);
+      }
