+      expandedIds,
+      setExpandedIds,
+      searchValue,
+      setSearchValue,
+      selectedProductId,
+      setSelectedProductId,
+      selectedEntryIds,
+      setSelectedEntryIds,
+      requestText,
+      setRequestText,
+      drafts,
+      setDrafts,
+      selectedProduct,
+      selectedIntentLabel,
+      productRequired,
+      optionalProduct,
+      detailsUseProductTree,
+      productEntries,
+      canUseFreeform,
+      canContinueDetails,
+      canOpenDetails,
+      canOpenDrafts,
+      canOpenReview,
+      replaceDraftsFromDetails,
+      removeDraft: (id) => setDrafts((prev) => prev.filter((draft) => draft.id !== id)),
+      editDraft,
+      resetSelectionForNewRequest,
+      goToStep,
+    }),
+    [
+      activeStep,
+      availableEntries,
+      canContinueDetails,
+      canOpenDetails,
+      canOpenDrafts,
+      canOpenReview,
+      canUseFreeform,
+      detailsUseProductTree,
+      drafts,
+      expandedIds,
+      intent,
+      mode,
+      optionalProduct,
+      productEntries,
+      productIndex,
+      productRequired,
+      requestText,
+      searchValue,
+      selectedEntryIds,
+      selectedIntentLabel,
+      selectedProduct,
+      selectedProductId,
+    ],
+  );
+
+  return (
+    <CertificationRequestContext.Provider value={value}>
+      {children}
+    </CertificationRequestContext.Provider>
+  );
+}
+
+export function useCertificationRequest(): CertificationRequestContextValue {
+  const context = useContext(CertificationRequestContext);
+  if (context === undefined) {
+    throw new Error("useCertificationRequest must be used within CertificationRequestProvider");
+  }
+  return context;
