from pathlib import Path
path = Path('/Users/psoudan/workspace/05-Procertus/Procertus-ui-experiment/apps/frontend-pt1-extranet-onboarding/src/features/certification-wizard/CertificationRequestWizard.tsx')
path.write_text(r'''import {
  CERTIFICATION_REQUEST_STEP_IDS,
  CertificationRequestProvider,
  PRODUCT_CERTIFICATION_ENTRY_IDS,
  getAvailableProductEntries,
  getCertificationOptionText,
  normalizeCertificationQuery,
  primaryIntentAvailability,
  useCertificationRequest,
} from "@procertus-ui/ui-certification";
import type {
  AvailableEntry,
  CertificationRequestDraft,
  CertificationRequestIntentId,
  CertificationRequestStepId,
  TreeNode,
} from "@procertus-ui/ui-certification";
import {
  Badge,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Field,
  FieldContent,
  FieldLabel,
  Input,
  Textarea,
} from "@procertus-ui/ui";
import {
  CertificationBadgeRow,
  CertificationIntentPicker,
  DraftRequestList,
  OnboardingStepper,
  ProductMultiSelect,
  ProductTreePanel,
  RequestPackageReview,
  StepLayout,
  defaultCertificationIntentOptionsEn,
} from "@procertus-ui/ui-lib";
import type {
  CertificationBadgeItem,
  CertificationIntentId,
  DraftRequestItem,
  OnboardingStepperStep,
  ProductMultiSelectOption,
  ProductTreeNode,
  ProductTreeProductNode,
  RequestPackageRow,
} from "@procertus-ui/ui-lib";
import { useMemo } from "react";

export type CertificationWizardDraft = CertificationRequestDraft;
type WizardStepId = CertificationRequestStepId;

export type CertificationRequestWizardProps = {
  mode: "onboarding" | "authenticated";
  initialDrafts?: CertificationWizardDraft[];
  initialStep?: WizardStepId | number;
  onCancel?: () => void;
  onComplete: (drafts: CertificationWizardDraft[]) => void;
};

function pathMatches(path: readonly string[], query: string) {
  if (!query) return true;
  return path.some((part) => part.toLocaleLowerCase("nl-BE").includes(query));
}

function toProductTreeNodes({
  nodes,
  entries,
  intent,
  selectedProductId,
  query,
  pathPrefix = [],
}: {
  nodes: readonly TreeNode[];
  entries: readonly AvailableEntry[];
  intent: CertificationRequestIntentId | undefined;
  selectedProductId: string | undefined;
  query: string;
  pathPrefix?: string[];
}): ProductTreeNode[] {
  return nodes.flatMap((node): ProductTreeNode[] => {
    const path = [...pathPrefix, node.label];
    if (node.kind === "product") {
      if (!pathMatches(path, query)) return [];
      const availability = primaryIntentAvailability(node, intent, entries);
      return [
        {
          kind: "product",
          id: node.id,
          label: node.label,
          productTypeId: node.productTypeStreamLabel,
          description: path.slice(0, -1).join(" › "),
          selectable: availability.available,
          statusLabel: availability.label,
          unavailableReason: availability.reason,
          selected: selectedProductId === node.id,
        },
      ];
    }

    const children = toProductTreeNodes({
      nodes: node.children ?? [],
      entries,
      intent,
      selectedProductId,
      query,
      pathPrefix: path,
    });
    const groupMatches = pathMatches(path, query);
    if (!groupMatches && children.length === 0) return [];
    return [{ kind: "group", id: node.id, label: node.label, children }];
  });
}

function badgeItemsForDraft(draft: CertificationWizardDraft): CertificationBadgeItem[] {
  return [
    {
      id: draft.id,
      shortLabel: draft.shortLabel,
      presentation: "chip",
      text: draft.value,
    },
  ];
}

function CertificationRequestWizardView({
  onCancel,
  onComplete,
}: Pick<CertificationRequestWizardProps, "onCancel" | "onComplete">) {
  const request = useCertificationRequest();
  const {
    mode,
    clusters,
    availableEntries,
    productIndex,
    activeStep,
    intent,
    setIntent,
    expandedIds,
    setExpandedIds,
    searchValue,
    setSearchValue,
    selectedProductId,
    setSelectedProductId,
    selectedEntryIds,
    setSelectedEntryIds,
    requestText,
    setRequestText,
    drafts,
    selectedProduct,
    selectedIntentLabel,
    productRequired,
    detailsUseProductTree,
    productEntries,
    canUseFreeform,
    canContinueDetails,
    canOpenDetails,
    canOpenDrafts,
    canOpenReview,
    replaceDraftsFromDetails,
    removeDraft,
    editDraft,
    resetSelectionForNewRequest,
    goToStep,
  } = request;

  const steps: OnboardingStepperStep[] = [
    {
      id: CERTIFICATION_REQUEST_STEP_IDS[0],
      title: "Intent",
      description: selectedIntentLabel ?? "Kies wat je nodig hebt",
      available: true,
    },
    {
      id: CERTIFICATION_REQUEST_STEP_IDS[1],
      title: productRequired ? "Product" : "Context",
      description: selectedProduct?.node.label ?? (productRequired ? "Zoek in de beslissingsboom" : "Beschrijf de aanvraag"),
      available: canOpenDetails,
    },
    {
      id: CERTIFICATION_REQUEST_STEP_IDS[2],
      title: "Drafts",
      description: drafts.length === 1 ? "1 conceptaanvraag" : `${drafts.length} conceptaanvragen`,
      available: canOpenDrafts,
    },
    {
      id: CERTIFICATION_REQUEST_STEP_IDS[3],
      title: "Review",
      description: "Controleer het pakket",
      available: canOpenReview,
    },
  ];

  const treeNodes = useMemo(
    () =>
      toProductTreeNodes({
        nodes: clusters,
        entries: availableEntries,
        intent,
        selectedProductId,
        query: normalizeCertificationQuery(searchValue),
      }),
    [availableEntries, clusters, intent, searchValue, selectedProductId],
  );

  const productOptions: ProductMultiSelectOption[] = useMemo(
    () =>
      productEntries.map(({ entry, availability }) => ({
        id: entry.id,
        label: entry.label,
        description: getCertificationOptionText(entry, availability.value),
      })),
    [productEntries],
  );

  const draftItems: DraftRequestItem[] = drafts.map((draft) => ({
    id: draft.id,
    title: draft.productLabel ? `${draft.label} voor ${draft.productLabel}` : draft.label,
    subtitle: draft.productPath ?? "Niet-productgebonden aanvraag",
    details: <CertificationBadgeRow items={badgeItemsForDraft(draft)} />,
  }));

  const reviewRows: RequestPackageRow[] = [
    { id: "intent", label: "Startintentie", value: selectedIntentLabel ?? "Nog niet gekozen" },
    { id: "mode", label: "Context", value: mode === "onboarding" ? "Anonieme onboarding" : "Aangemelde aanvraag" },
    ...drafts.map((draft, index) => ({
      id: draft.id,
      label: `Aanvraag ${index + 1}`,
      value: draft.productLabel ? `${draft.label} · ${draft.productLabel}` : draft.label,
    })),
  ];

  const goNext = () => {
    if (activeStep === 1) {
      replaceDraftsFromDetails();
    }
    if (activeStep === steps.length - 1) {
      onComplete(drafts);
      return;
    }
    goToStep(activeStep + 1);
  };

  const primaryDisabled =
    (activeStep === 0 && !intent) ||
    (activeStep === 1 && !canContinueDetails) ||
    (activeStep >= 2 && drafts.length === 0);

  const selectedProductAvailabilityCopy =
    selectedProduct && intent ? primaryIntentAvailability(selectedProduct.node, intent, availableEntries) : undefined;

  return (
    <StepLayout
      className="max-w-6xl"
      variant="wizard"
      stepper={
        <OnboardingStepper
          steps={steps}
          activeStep={activeStep}
          onStepChange={goToStep}
          interactive
        />
      }
      title={
        activeStep === 0
          ? "Waarvoor wil je een aanvraag starten?"
          : activeStep === 1
            ? productRequired
              ? "Selecteer het producttype"
              : "Beschrijf de aanvraagcontext"
            : activeStep === 2
              ? "Conceptaanvragen"
              : "Aanvraagpakket controleren"
      }
      description={
        activeStep === 0
          ? "We starten met de inhoudelijke aanvraag. Account- en organisatieactivatie komen pas nadat je zeker bent dat je dit pakket wilt indienen."
          : activeStep === 1
            ? productRequired
              ? "Alle productcategorieën blijven zichtbaar. Producttypes waarvoor de gekozen intentie niet beschikbaar is, tonen waarom ze niet gekozen kunnen worden."
              : "Niet elke attestering begint bij een product. Geef eerst de aanvraagcontext; voeg optioneel een product toe wanneer dat helpt."
            : activeStep === 2
              ? "Een wizardrun kan meerdere conceptaanvragen toevoegen wanneer het gekozen product meerdere beschikbare certificaties of attesten ondersteunt."
              : "Dit is de samenvatting die terugkeert naar de onboarding-intake of naar de aangemelde aanvraaglijst."
      }
      stepLabel={`Stap ${activeStep + 1} van ${steps.length}`}
      backAction={
        activeStep > 0
          ? { label: "Terug", onClick: () => goToStep(Math.max(0, activeStep - 1)) }
          : onCancel
            ? { label: "Annuleren", onClick: onCancel }
            : undefined
      }
      secondaryAction={
        activeStep === 2
          ? {
              label: "Nog een aanvraag toevoegen",
              onClick: resetSelectionForNewRequest,
            }
          : undefined
      }
      primaryAction={{
        label: activeStep === steps.length - 1 ? "Gebruik dit pakket" : "Verder",
        onClick: goNext,
        disabled: primaryDisabled,
      }}
    >
      {activeStep === 0 ? (
        <CertificationIntentPicker
          value={intent as CertificationIntentId | undefined}
          onValueChange={(nextIntent) => setIntent(nextIntent as CertificationRequestIntentId)}
          options={defaultCertificationIntentOptionsEn}
        />
      ) : null}

      {activeStep === 1 ? (
        <div className="space-y-4">
          {canUseFreeform ? (
            <Card>
              <CardHeader>
                <CardTitle>Aanvraagcontext</CardTitle>
                <CardDescription>
                  Voor {selectedIntentLabel} volstaat in dit prototype een korte beschrijving. Een productselectie
                  is optioneel waar het Procertus-model productinformatie bevat.
                </CardDescription>
              </CardHeader>
              <CardContent>
                <Field>
                  <FieldLabel htmlFor="request-context">Beschrijf de aanvraag</FieldLabel>
                  <FieldContent>
                    <Textarea
                      id="request-context"
                      value={requestText}
                      onChange={(event) => setRequestText(event.target.value)}
                      placeholder="Bijvoorbeeld: technisch attest voor een innovatieve toepassing op een concrete werf..."
                      className="min-h-28"
                    />
                  </FieldContent>
                </Field>
              </CardContent>
            </Card>
          ) : null}

          {detailsUseProductTree ? (
            <div className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)]">
              <ProductTreePanel
                className="max-w-none"
                title="Product zoeken"
                description="Drill down in de Procertus-beslissingsboom of filter op productnaam."
                searchValue={searchValue}
                onSearchChange={setSearchValue}
                searchPlaceholder="Zoek product of categorie..."
                nodes={treeNodes}
                expandedIds={expandedIds}
                onToggle={(groupId, open) => {
                  setExpandedIds((prev) => {
                    const set = new Set(prev);
                    if (open) set.add(groupId);
                    else set.delete(groupId);
                    return Array.from(set);
                  });
                }}
                onSelectProduct={(product: ProductTreeProductNode) => {
                  setSelectedProductId(product.id);
                  const selected = productIndex.get(product.id);
                  const available = getAvailableProductEntries(selected?.node, availableEntries);
                  const preferred =
                    intent === "product-certification"
                      ? available.filter(({ entry }) => PRODUCT_CERTIFICATION_ENTRY_IDS.has(entry.id))
                      : available.filter(({ entry }) => entry.id === intent);
                  setSelectedEntryIds((preferred.length ? preferred : available.slice(0, 1)).map(({ entry }) => entry.id));
                }}
                showSearch
              />
              <Card className="h-fit">
                <CardHeader>
                  <CardTitle>Beschikbare opties</CardTitle>
                  <CardDescription>
                    {selectedProduct
                      ? selectedProductAvailabilityCopy?.available
                        ? "Kies een of meer certificaties/attesten voor dit product."
                        : selectedProductAvailabilityCopy?.reason
                      : "Selecteer eerst een beschikbaar producttype."}
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  {selectedProduct ? (
                    <>
                      <div className="rounded-md border border-border/60 bg-muted/20 p-3">
                        <p className="font-medium">{selectedProduct.node.label}</p>
                        <p className="text-sm text-muted-foreground">
                          {selectedProduct.path.slice(0, -1).join(" › ")}
                        </p>
                      </div>
                      <ProductMultiSelect
                        selectedIds={selectedEntryIds}
                        onChange={setSelectedEntryIds}
                        options={productOptions}
                        legend="Toe te voegen aanvragen"
                        description="Alle beschikbare productgebonden opties blijven combineerbaar binnen dezelfde run."
                        emptyMessage="Geen productgebonden opties beschikbaar voor dit product."
                      />
                    </>
                  ) : (
                    <div className="space-y-3 text-sm text-muted-foreground">
                      <p>
                        De boom toont ook producttypes waarvoor {selectedIntentLabel ?? "de gekozen intentie"} niet
                        mogelijk is. Die rijen blijven zichtbaar met uitleg, maar kunnen niet gekozen worden.
                      </p>
                      <Input value={searchValue} onChange={(event) => setSearchValue(event.target.value)} placeholder="Snel zoeken..." />
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          ) : null}
        </div>
      ) : null}

      {activeStep === 2 ? (
        <DraftRequestList
          title="Concepten in deze aanvraag"
          description="Controleer de aangemaakte concepten. In deze prototypefase opent bewerken opnieuw de detailstap."
          drafts={draftItems}
          onEdit={editDraft}
          onRemove={removeDraft}
        />
      ) : null}

      {activeStep === 3 ? (
        <div className="grid gap-4 lg:grid-cols-[minmax(0,1fr)_18rem]">
          <RequestPackageReview
            title="Aanvraagpakket"
            description="Deze gegevens worden samen met de onboarding-intake of de gekende organisatiecontext ingediend."
            rows={reviewRows}
            notice={
              drafts.length > 1 ? (
                <span>
                  <Badge variant="secondary">{drafts.length} concepten</Badge> worden samen gebundeld in dit pakket.
                </span>
              ) : undefined
            }
          />
          <Card className="h-fit">
            <CardHeader>
              <CardTitle>Prototypegedrag</CardTitle>
              <CardDescription>
                Er is nog geen API. De volgende stap bewaart de concepten in de app-state en simuleert indien nodig
                accountactivatie.
              </CardDescription>
            </CardHeader>
          </Card>
        </div>
      ) : null}
    </StepLayout>
  );
}

export function CertificationRequestWizard({
  mode,
  initialDrafts = [],
  initialStep,
  onCancel,
  onComplete,
}: CertificationRequestWizardProps) {
  return (
    <CertificationRequestProvider mode={mode} initialDrafts={initialDrafts} initialStep={initialStep}>
      <CertificationRequestWizardView onCancel={onCancel} onComplete={onComplete} />
    </CertificationRequestProvider>
  );
}
''')
